/* Botões e Cards (design system básico) */

:root {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --danger: #ef4444;
  --border: rgba(255, 255, 255, 0.10);
  --radius: 14px;
  --shadow-1: 0 6px 16px rgba(0, 0, 0, 0.12);
  --shadow-2: 0 16px 40px rgba(0, 0, 0, 0.16);
}

.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  padding: 10px 14px;
  border-radius: 12px;
  border: 1px solid transparent;
  font-weight: 600;
  cursor: pointer;
  transition: transform 150ms ease, opacity 150ms ease;
}

.btn:focus-visible {
  outline: 3px solid var(--accent);
  outline-offset: 3px;
}

.btn:hover {
  transform: translateY(-1px);
  opacity: 0.95;
}

.btn:disabled {
  opacity: 0.55;
  cursor: not-allowed;
  transform: none;
}

.btn.primary {
  background: var(--accent);
  color: #0b0f19;
}

.btn.ghost {
  background: transparent;
  color: var(--text);
  border-color: var(--border);
}

.btn.danger {
  background: var(--danger);
  color: #0b0f19;
}

.card {
  background: var(--panel);
  color: var(--text);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  box-shadow: var(--shadow-1);
  overflow: hidden;
}

.card-inner {
  display: grid;
  gap: 10px;
  padding: 16px;
}

.card.clickable {
  transition: transform 180ms ease, box-shadow 180ms ease;
}

.card.clickable:hover,
.card.clickable:focus-visible {
  transform: translateY(-2px);
  box-shadow: var(--shadow-2);
}

.muted {
  color: var(--muted);
}
